# variables.tf
variable "allowed_regions" {
  description = "Regions allowed for Corp workloads"
  type        = list(string)
  default     = ["eastus", "eastus2", "westeurope"]
}

variable "corp_subscriptions" {
  description = "Map of Corp subscription IDs to their tier (prod or nonprod)"
  type        = map(string)  # { sub_id = "prod" | "nonprod" }
  default     = {}
}

variable "sandbox_subscription_ids" {
  type    = list(string)
  default = []
}

# main.tf
data "azurerm_client_config" "current" {}

data "azurerm_management_group" "root" {
  name = data.azurerm_client_config.current.tenant_id
}

locals {
  top_level = {
    platform = "Platform"
    corp     = "Corp (Regulated Workloads)"
    online   = "Online"
    sandbox  = "Sandbox"
  }
  platform_children = {
    connectivity = { display = "Connectivity", parent = "platform" }
    identity     = { display = "Identity",     parent = "platform" }
    management   = { display = "Management",   parent = "platform" }
  }
}

resource "azurerm_management_group" "top" {
  for_each                   = local.top_level
  name                       = "mg-${each.key}"
  display_name               = each.value
  parent_management_group_id = data.azurerm_management_group.root.id
}

resource "azurerm_management_group" "platform_children" {
  for_each                   = local.platform_children
  name                       = "mg-platform-${each.key}"
  display_name               = each.value.display
  parent_management_group_id = azurerm_management_group.top["platform"].id
}

# Corp prod/nonprod sub-groups
resource "azurerm_management_group" "corp_prod" {
  name                       = "mg-corp-prod"
  display_name               = "Corp - Production"
  parent_management_group_id = azurerm_management_group.top["corp"].id
}

resource "azurerm_management_group" "corp_nonprod" {
  name                       = "mg-corp-nonprod"
  display_name               = "Corp - Non-Production"
  parent_management_group_id = azurerm_management_group.top["corp"].id
}

# Attach Corp subscriptions to the right tier
resource "azurerm_management_group_subscription_association" "corp" {
  for_each = var.corp_subscriptions

  management_group_id = each.value == "prod" ?
    azurerm_management_group.corp_prod.id :
    azurerm_management_group.corp_nonprod.id

  subscription_id = "/subscriptions/${each.key}"
}

# Attach Sandbox subscriptions
resource "azurerm_management_group_subscription_association" "sandbox" {
  for_each = toset(var.sandbox_subscription_ids)

  management_group_id = azurerm_management_group.top["sandbox"].id
  subscription_id     = "/subscriptions/${each.value}"
}

# policies.tf — root-level and Corp-level policy assignments

data "azurerm_policy_definition" "require_tag" {
  display_name = "Require a tag on resources"
}

data "azurerm_policy_definition" "allowed_locations" {
  display_name = "Allowed locations"
}

# Root: require 'environment' tag on all resources
resource "azurerm_management_group_policy_assignment" "require_env_tag" {
  name                 = "require-env-tag"
  management_group_id  = data.azurerm_management_group.root.id
  policy_definition_id = data.azurerm_policy_definition.require_tag.id
  parameters = jsonencode({
    tagName = { value = "environment" }
  })
}

# Corp: restrict to allowed regions
resource "azurerm_management_group_policy_assignment" "corp_regions" {
  name                 = "corp-allowed-regions"
  management_group_id  = azurerm_management_group.top["corp"].id
  policy_definition_id = data.azurerm_policy_definition.allowed_locations.id
  parameters = jsonencode({
    listOfAllowedLocations = { value = var.allowed_regions }
  })
}

# Corp-Prod: additional deny — no public IP on VMs
data "azurerm_policy_definition" "deny_public_ip_vm" {
  display_name = "Network interfaces should not have public IPs"
}

resource "azurerm_management_group_policy_assignment" "deny_vm_public_ip_prod" {
  name                 = "deny-vm-public-ip-prod"
  management_group_id  = azurerm_management_group.corp_prod.id
  policy_definition_id = data.azurerm_policy_definition.deny_public_ip_vm.id
  enforce              = true
}

# Deploy to multiple tenants using provider aliases
provider "azurerm" {
  alias           = "prod_tenant"
  tenant_id       = var.prod_tenant_id
  subscription_id = var.prod_mgmt_subscription_id
  features {}
}

provider "azurerm" {
  alias           = "dev_tenant"
  tenant_id       = var.dev_tenant_id
  subscription_id = var.dev_mgmt_subscription_id
  features {}
}

# Create the same hierarchy in both tenants
module "hierarchy_prod" {
  source    = "./modules/mg-hierarchy"
  providers = { azurerm = azurerm.prod_tenant }
  allowed_regions = ["eastus", "westeurope"]
}

module "hierarchy_dev" {
  source    = "./modules/mg-hierarchy"
  providers = { azurerm = azurerm.dev_tenant }
  allowed_regions = ["eastus", "eastus2", "westeurope", "australiaeast"]
}
